// ── Server-side validation (mirrors frontend rules) ──────────────
const body = $input.first().json.body || $input.first().json;

const errors = [];

const patientName      = String(body.patient_name      || '').trim();
const phoneRaw         = String(body.phone_number      || '').trim();
const dob              = String(body.dob               || '').trim();
const sex              = String(body.sex               || '').trim();
const hospitalName     = String(body.hospital_name     || '').trim();
const doctorName       = String(body.doctor_name       || '').trim();
const visitDate        = String(body.visit_date        || '').trim();
const followUpRequired = String(body.follow_up_required|| '').trim();
const followUpDate     = String(body.follow_up_date    || '').trim();

// Required fields
if (!patientName || patientName.length < 2)
  errors.push('patient_name: required, min 2 characters');
if (!/^[0-9]{10}$/.test(phoneRaw))
  errors.push('phone_number: must be exactly 10 digits (no country code)');
if (!hospitalName)
  errors.push('hospital_name: required');
if (!doctorName)
  errors.push('doctor_name: required');
if (!visitDate || !/^\d{4}-\d{2}-\d{2}$/.test(visitDate))
  errors.push('visit_date: required, format YYYY-MM-DD');
if (!['Yes','No'].includes(followUpRequired))
  errors.push('follow_up_required: must be Yes or No');

// Conditional follow-up date
if (followUpRequired === 'Yes') {
  if (!followUpDate || !/^\d{4}-\d{2}-\d{2}$/.test(followUpDate))
    errors.push('follow_up_date: required when follow_up_required is Yes');
  else if (visitDate && followUpDate <= visitDate)
    errors.push('follow_up_date: must be after visit_date');
}

// Optional field validation
if (sex && !['Male','Female','Other'].includes(sex))
  errors.push('sex: must be Male, Female, or Other');

if (dob && !/^\d{4}-\d{2}-\d{2}$/.test(dob))
  errors.push('dob: format must be YYYY-MM-DD');

if (errors.length > 0) {
  return [{ json: { _valid: false, _errors: errors, _phone: null } }];
}

// Normalise phone to E.164 (+91)
const phoneE164 = '+91' + phoneRaw;

return [{
  json: {
    _valid:          true,
    _errors:         [],
    patient_name:    patientName,
    phone:           phoneE164,
    dob:             dob || null,
    sex:             sex || null,
    clinic_name:     hospitalName,
    doctor_name:     doctorName,
    visit_date:      visitDate,
    follow_up_required: followUpRequired,
    follow_up_date:  followUpRequired === 'Yes' ? followUpDate : null,
    _raw_phone:      phoneRaw
  }
}];

// Merge count from previous step with validated fields from If Valid
const validated = $('Validate and Map Fields').first().json;
const count     = $input.first().json.total || 0;

// PAT-0001, PAT-0002 …
const seq         = String(count + 1).padStart(4, '0');
const patientCode = 'PAT-' + seq;

const now = new Date().toISOString();

return [{
  json: {
    ...validated,
    patient_code: patientCode,
    status:       'Pending',
    message_count: 0,
    created_at:   now,
    updated_at:   now,
  }
}];
